examples.code:
#include <stdio.h>
int main() {
    int age;
    printf("Enter your age: ");
    scanf("%d", &age);  // & gives the address!
    printf("You are %d years old\n", age);
    return 0;
}

int n;
float f;
char c;

scanf("%d", &n);  // read integer
scanf("%f", &f);  // read float
scanf(" %c", &c); // read char (space before %c skips whitespace)

int x;

// CORRECT:
scanf("%d", &x);  // &x = address of x ✅

// WRONG — undefined behavior, likely crash:
scanf("%d", x);   // x = current value, not address ❌

// Reading a string (char array) — NO & needed:
char name[20];
scanf("%s", name); // arrays are already addresses!

